function saveProfile(p: Profile) {
  if (typeof window === "undefined") return;
  walletSetItem("orderlyProfile", JSON.stringify(p));
}

const VAULT_ADDRESS = "0x816f722424b49cf1275cc86da9840fbd5a6167e9";
const DELEGATE_DATA = [
  "0x9f3b6e8a1c4d7f2e5b8a0c3d6f9e2b5a8c1d4f7e",
  "0x71C7656EC7ab88b098defB751B7401B5f6d8976F",
];

function abbreviate(str: string, start = 6, end = 4): string {
  if (!str || str.length <= start + end + 3) return str;
  return str.slice(0, start) + "..." + str.slice(-end);
}

async function fetchBuilderAccountId(
  address: string,
  brokerId: string
): Promise<string | null> {
  try {
    const payload = await apiClient<{
      success?: boolean;
      message?: string;
      data?: { account_id?: string };
    }>({
      endpoint: `/v1/get_account?address=${encodeURIComponent(address)}&broker_id=${encodeURIComponent(brokerId)}`,
      token: null,
      showToastOnError: false,
    });
    if (payload?.success && payload.data?.account_id)
      return payload.data.account_id;
    return null;
  } catch (error) {
    const status = (error as Error & { status?: number }).status;
    const data = (error as Error & { data?: { message?: string } }).data;
    if (
      (status === 400 || status === 404) &&
      /account not found|not exist/i.test(data?.message || "")
    )
      return null;
    throw new Error(
      data?.message || "Failed to check admin account registration."
    );
  }
}

async function registerBuilderAccount(input: {
  address: string;
  chainId: number | string;
  brokerId: string;
  walletClient: WalletClient;
}): Promise<string> {
  const existingAccountId = await fetchBuilderAccountId(
    input.address,
    input.brokerId
  );
  if (existingAccountId) return existingAccountId;

  if (!input.address) {
    throw new Error("Wallet address not available");
  }

  const registrationNonce = await getRegistrationNonce(input.address);

  const signer = await walletClientToEthersSigner(input.walletClient);
  const message = {
    brokerId: input.brokerId,
    chainId: Number(input.chainId),
    timestamp: Date.now(),
    registrationNonce,
  };
  const signature = await signer.signTypedData(
    getOffChainDomain(input.chainId),
    REGISTRATION_MESSAGE_TYPES,
    message
  );
  const registerPayload = await apiClient<{
    success?: boolean;
    message?: string;
    data?: { account_id?: string };
  }>({
    endpoint: "/v1/register_account",
    method: "POST",
    token: null,
    body: { message, signature, userAddress: input.address },
    showToastOnError: false,
  });
  if (!registerPayload.success || !registerPayload.data?.account_id)
    throw new Error(
      registerPayload.message || "Failed to register admin account."
    );
  return registerPayload.data.account_id;
}

